%[text] # **Proxigram** 
%[text] **Creation of a simple proxigram**
%[text] Materials often exhibit concentration gradients or sections, which are enriched or depleted with respect to a specific element. Therefore, the evaluation of the concentration of a specified species can be of high interest.
%[text] By means of **proxi**mity histo**grams** (**proxigrams**), the user can plot the concentration profile of a species with respect to the distance to a defined surface (e.g., isosurface, grain boundary).
%%
%[text] For the creation of a proxigram, the user needs to define an interface, which must be a 1x1 structure with fields of faces and vertices (hence often called fv), e.g., an isosurface (see the live script ***Isosurface***).
%[text] Additionally, the pos file of the species (*posSpecies*), the parent pos file (*pos*), and the bin width (*bin*) must be defined.
%[text] The outputs of the function *patchCreateProxigram* are the x- and y-values of the resulting plot, represented by *binVector* and *proxi*, respectively.
pos = pos; % selection of pos file (initial or decomposed); must be present in the workspace %[control:dropdown:8af9]{"position":[7,10]}
posSpecies = pos(pos.ion == 'H2',:); % specification of wanted species, input as atomic symbol (e.g., C) %[control:editfield:003e]{"position":[30,32]}
interface = fv2; % input of interface structure; must be present in workspace %[control:editfield:2dc4]{"position":[13,16]}
bin = 0.5; % definition of bin width in nm, scalar %[control:editfield:85f0]{"position":[7,10]}
[proxi, binVector] = patchCreateProxigram(posSpecies,pos,interface,bin); % creation of proxigram %[output:55fc427c]
  %[control:button:959f]{"position":[1,2]}
%%
%[text] ## Calculation of a proxigram for different ions
%[text] the binVector stays the same for every ion. All concentration values are stored in the variable proxiAll
species = {'H2', 'Ni', 'Al', 'Co'}; % change ions to the desired ones %[control:editfield:627e]{"position":[12,16]} %[control:editfield:2593]{"position":[18,22]} %[control:editfield:4cc6]{"position":[24,28]} %[control:editfield:3955]{"position":[30,34]}
interface = fv2; % input of interface structure; must be present in workspace %[control:editfield:0d05]{"position":[13,16]}
bin = 0.5; % definition of bin width in nm, scalar %[control:editfield:13e7]{"position":[7,10]}
proxiAll = table();

for i = 1:length(species) %[output:group:945343bc]
    posSpecies = pos(pos.ion == species(1,i),:);
    [proxi, binVector] = patchCreateProxigram(posSpecies,pos,interface,bin); %[output:44cca022] %[output:9e44888e] %[output:689a5fc5] %[output:4cbcc6bd]
    if i == 1  
        proxi = proxi*100;
        proxiAll = addvars(proxiAll, binVector', proxi','NewVariableNames', {'binVector', species{1,i}} );
    else
        proxi = proxi*100;
        proxiAll = addvars(proxiAll, proxi','NewVariableNames', species{1,i} );
    end
    
end %[output:group:945343bc]
  %[control:button:2c2b]{"position":[1,2]}
%%
%[text] ## Plot the concentration of more ions in one plot
species = {'Cr', 'Ni', 'Al', 'Co'}; % change ions to the desired ones %[control:editfield:13f1]{"position":[12,16]} %[control:editfield:9e10]{"position":[18,22]} %[control:editfield:0ee1]{"position":[24,28]} %[control:editfield:66ad]{"position":[30,34]}
figure;
lineWidth = 2;

for k = 1:length(species)
    idxElement = find(string(proxiAll.Properties.VariableNames) == species(1,k));
    plot(proxiAll.binVector, table2array(proxiAll(:,idxElement)), 'DisplayName', species{1,k}, 'LineWidth', lineWidth, 'Color', colorScheme.color(colorScheme.ion == species{1,k},:));
    hold on
end

hold off
legend
xlabel('distance [nm]');
ylabel('concentration [%]');
  %[control:button:2a83]{"position":[1,2]}
%[text] 

